import{_ as e}from"./chunks/POCKET.DAcsAyoE.js";import{_ as o}from"./chunks/chooseRx.dmJ4OLlk.js";import{_ as r,c as a,o as n,ag as s}from"./chunks/framework.DRADY2L-.js";const b=JSON.parse('{"title":"The Cheapest Start","description":"::: warning Important Rule Anything cheaper than the components on this list is either a disposable \\"toy\\" or outright junk that will ruin your experience wit...","frontmatter":{"description":"::: warning Important Rule Anything cheaper than the components on this list is either a disposable \\"toy\\" or outright junk that will ruin your experience wit...","gitAuthors":["mituritsyn"]},"headers":[],"relativePath":"intro/cheapest_start.md","filePath":"en/intro/cheapest_start.md","lastUpdated":1774733793000}'),i={name:"intro/cheapest_start.md"};function l(h,t,c,d,p,u){return n(),a("div",null,[...t[0]||(t[0]=[s('<h1 id="the-cheapest-start" tabindex="-1">The Cheapest Start <a class="header-anchor" href="#the-cheapest-start" aria-label="Permalink to &quot;The Cheapest Start&quot;">​</a></h1><div class="warning custom-block"><p class="custom-block-title">Important Rule</p><p>Anything cheaper than the components on this list is either a disposable &quot;toy&quot; or outright junk that will ruin your experience with the hobby. You must understand that buying the absolute cheapest gear comes with risks, but we&#39;ve tried to minimize them in this list.</p></div><h2 id="_1-radio-transmitter" tabindex="-1">1. Radio Transmitter <a class="header-anchor" href="#_1-radio-transmitter" aria-label="Permalink to &quot;1. Radio Transmitter&quot;">​</a></h2><p>It must have <strong>OpenTX</strong> or <strong>EdgeTX</strong> firmware and the <strong>ELRS</strong> protocol. This guarantees that it will have all the necessary features, you&#39;ll always be able to find help with your ideas or issues, and you can use it with any simulator and almost any modern FPV drone.</p><p>The most budget-friendly option running EdgeTX is the <strong>RadioMaster Pocket ELRS</strong>. In general, you can safely buy almost any radio from RadioMaster, except for the <em>Zorro</em> and <em>T8 Lite</em> models — they have certain quirks.</p><p class="image-container"><img src="'+e+'" height="400" alt="RadioMaster Pocket Transmitter" title="RadioMaster Pocket Transmitter"></p><h2 id="_2-radio-control-system-protocol" tabindex="-1">2. Radio Control System (Protocol) <a class="header-anchor" href="#_2-radio-control-system-protocol" aria-label="Permalink to &quot;2. Radio Control System (Protocol)&quot;">​</a></h2><p>This is your communication protocol. Choose <strong>ExpressLRS (ELRS)</strong> and only that! Both on the radio (look for <em>Pocket ELRS</em>) and the built-in receiver on the drone itself (look for <em>ELRS 2.4G</em> in the drone specs).</p><p>MPM (4-in-1) and classic CC2500 chips are an absolute no-go — they are outdated systems! If you have a Whoop drone with a built-in FrSky or FlySky receiver, you&#39;re better off throwing it away (or soldering a tiny external ELRS receiver if you know how).</p><p class="image-container"><img src="'+o+'" height="400" alt="Choosing an FPV protocol and receiver" title="Examples of quadcopter receivers"></p><h2 id="_3-video-goggles" tabindex="-1">3. Video Goggles <a class="header-anchor" href="#_3-video-goggles" aria-label="Permalink to &quot;3. Video Goggles&quot;">​</a></h2><p>In the vast majority of cases, a beginner should consider buying the <strong>DJI Goggles N3</strong> - it&#39;s not the coolest solution technically, but it&#39;s the cheapest relevant digital system from DJI. An alternative in the same price range is the <strong>Walksnail Avatar HD Goggles L</strong>. It&#39;s better to avoid Skyzone (<em>Skyzone Cobra</em>), as they are becoming obsolete and are priced comparably to cheap digital systems.</p><p>If you have absolutely no money, your choice is the cheapest analog system:</p><ul><li><strong>BetaFPV VR03 / VR04</strong> (no diversity, but compact and cheap);</li><li><strong>Eachine EV800D</strong> / <strong>EV800DM</strong> (Attention: look only for original ones with &quot;Eachine&quot; written on the front, do not buy clones!).</li></ul><h2 id="_4-tiny-whoop-drone" tabindex="-1">4. Tiny Whoop (Drone) <a class="header-anchor" href="#_4-tiny-whoop-drone" aria-label="Permalink to &quot;4. Tiny Whoop (Drone)&quot;">​</a></h2><p>In the ultra-budget segment, there is only one option — tiny whoops. These are small drones with prop guards that are ideal for flying indoors or outside in calm weather. Look for 65-75mm ELRS whoop series from <strong>HappyModel</strong> (e.g., <em>Mobula 6 2024</em>) or <strong>BetaFPV</strong> (<em>Meteor65-75 / Air65</em> / pro). <strong>Do not buy the Cetus series under any circumstances.</strong></p><p>Buying larger whoops (85mm+) as your very first drone doesn&#39;t make sense: they are too big and heavy for flying properly in an apartment, and outdoors it is more fun to fly a regular drone (without ducts/prop guards).</p><h2 id="_5-charger" tabindex="-1">5. Charger <a class="header-anchor" href="#_5-charger" aria-label="Permalink to &quot;5. Charger&quot;">​</a></h2><ul><li><strong>VIFLY WhoopStor V3</strong> - an inexpensive charger for <code>1S</code> whoop batteries with a Storage function.</li><li>If you plan to fly quadcopters with 2-to-6-cell batteries (<code>2S-6S</code>), you should immediately look at powerful chargers from <strong>ISDT</strong>, <strong>HOTA</strong>, or <strong>ToolkitRC</strong>.</li><li>For those who like to experiment — the portable power bank-style charger <em>GEPRC WooPower</em>.</li></ul><h2 id="_6-batteries" tabindex="-1">6. Batteries <a class="header-anchor" href="#_6-batteries" aria-label="Permalink to &quot;6. Batteries&quot;">​</a></h2><p>Make sure to choose the new connectors: <strong>BT2.0</strong> or <strong>A30</strong> (they are the same form factor). If the drone has an old <code>PH2.0</code> connector, it&#39;s better to solder a new connector onto the drone.</p><ul><li><strong>Top-tier (expensive):</strong> Tattu, Dogcom.</li><li><strong>Budget:</strong> Ovonic, BetaFPV Lava, GNB.</li></ul><hr><div class="danger custom-block"><p class="custom-block-title">DO NOT BUY UNDER ANY CIRCUMSTANCES!</p><p><strong>&quot;All-in-One&quot; Ready-to-Fly (RTF) kits:</strong> BetaFPV Aquila, Cetus, Emax Tinyhawk BTF/RTF kits, GEPRC TinyGO.</p><p>Especially avoid ready-to-fly kits (drone + radio + goggles in one bag). They will bring you nothing but problems, and they <strong>cannot be upgraded</strong> — you will have to replace almost the entire kit, which will end up being much more expensive.</p><p><em>(For a bit more detail on why you shouldn&#39;t buy a Cetus — read <a href="/shop/set#why-shouldn-t-you-buy-a-cetus">this post</a>).</em></p><p><strong>Conclusion:</strong> Any cheap RTF set will have issues with setup, compatibility, and replacing parts. People in community chats simply won&#39;t be able to help you — it&#39;s better to stay away from these boxes from the start.</p></div><blockquote><p><strong>P.S.</strong> It&#39;s better to decide on the style and conditions you want to fly in first, and <strong>adjust your budget to your goal</strong>, not the other way around.<br><a href="/intro/beginning">👈 Back: Getting started</a></p></blockquote>',25)])])}const f=r(i,[["render",l]]);export{b as __pageData,f as default};
